import React, { useEffect, useState } from 'react';
import logService from '../services/logService';
function UserLogs(){
  const [logs,setLogs]=useState([]);
  useEffect(()=>{ (async()=>{ try{ const res=await logService.getUserLogs(); setLogs(res); }catch(e){ console.error(e); } })(); },[]);
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 flex flex-col items-center p-8">
      <div className="w-full max-w-4xl bg-white rounded-2xl shadow-lg p-8">
        <h2 className="text-3xl font-bold mb-6 text-blue-700">My Activity Logs</h2>
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white rounded-lg shadow border">
            <thead className="bg-blue-100">
              <tr>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">ID</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Action</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">File</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Status</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Time</th>
              </tr>
            </thead>
            <tbody>
              {logs.map(l => (
                <tr key={l.id} className="border-t hover:bg-blue-50 transition">
                  <td className="py-2 px-4">{l.id}</td>
                  <td className="py-2 px-4">{l.action}</td>
                  <td className="py-2 px-4">{l.file_id}</td>
                  <td className="py-2 px-4">{l.status}</td>
                  <td className="py-2 px-4">{new Date(l.timestamp).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
export default UserLogs;
